Javascript.miscCode:
		  
		  Party.initialise = function() 
		  { 
				dom = getList("../LOV/PartyList.xml"); 
				Services.addNode(dom, REF_DATA_XPATH);
				return false; 
		  }
		  
		  	Party.componentName = "Party making the application"
		  	Party.srcData 		= REF_DATA_XPATH + "/PartyList";
			Party.rowXPath 	  	= "Party";
			Party.keyXPath 	  	= "Value";
			
			function PartyLOVButton() {}
			PartyLOVButton.tabIndex = __tabIdx++;
			
			function PartyLOVGrid() {};
			PartyLOVGrid.dataBinding = Party.dataBinding;
			PartyLOVGrid.srcData 	 = REF_DATA_XPATH + "/PartyList";
			PartyLOVGrid.rowXPath    = "Party";
			PartyLOVGrid.keyXPath    = "Value";
			PartyLOVGrid.columns     = [
				{xpath: "Value"},
				{xpath: "Description"}
			];
			PartyLOVGrid.raise = {
				eventBinding: {
					singleClicks: [ {element: "PartyLOVButton"} ],
					keys: [ { key: Key.F6, element: "Party" } ]
				}
			};
